1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_SURCHARGE = 10;
3	const BLOCK_OF_THREE_PREMIUM = 60;
4	const BLOCK_SIZE = 3;
5	const CURSE_SURCHARGE_RATE = 0.5;
6	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
7	const HIGH_ENCHANTMENT_THRESHOLD = 5;
8	const LOYALTY_DISCOUNT_RATE = 0.2;
9	const LOYALTY_YEARS_THRESHOLD = 2;
10	
11	const BASE_PREMIUMS: Record<string, number> = {
12	  sword: 100,
13	  amulet: 60,
14	  staff: 80,
15	  potion: 40,
16	  rune: 25,
17	  moonstone: 25,
18	};
19	
20	type Item = { type: string; cursed?: boolean; enchantment?: number };
21	
22	function isHighlyEnchanted(item: Item): boolean {
23	  return item.enchantment !== undefined && item.enchantment >= HIGH_ENCHANTMENT_THRESHOLD;
24	}
25	
26	function surchargeRate(item: Item): number {
27	  return (item.cursed ? CURSE_SURCHARGE_RATE : 0)
28	    + (isHighlyEnchanted(item) ? HIGH_ENCHANTMENT_SURCHARGE_RATE : 0);
29	}
30	
31	function itemBasePremium(item: Item): number {
32	  const base = BASE_PREMIUMS[item.type];
33	  return base + base * surchargeRate(item);
34	}
35	
36	function sumIndividualBasePremiums(items: Item[]): number {
37	  return items.reduce((sum, item) => sum + itemBasePremium(item), 0);
38	}
39	
40	function groupByType(items: Item[]): Record<string, Item[]> {
41	  const groups: Record<string, Item[]> = {};
42	  for (const item of items) {
43	    if (!groups[item.type]) groups[item.type] = [];
44	    groups[item.type].push(item);
45	  }
46	  return groups;
47	}
48	
49	function premiumForGroup(groupItems: Item[]): number {
50	  return groupItems.length === BLOCK_SIZE
51	    ? BLOCK_OF_THREE_PREMIUM
52	    : sumIndividualBasePremiums(groupItems);
53	}
54	
55	function calculateBasePremium(items: Item[]): number {
56	  const groups = groupByType(items);
57	  return Object.values(groups).reduce((total, group) => total + premiumForGroup(group), 0);
58	}
59	
60	function loyaltyDiscount(basePremium: number, years: number): number {
61	  return years >= LOYALTY_YEARS_THRESHOLD ? basePremium * LOYALTY_DISCOUNT_RATE : 0;
62	}
63	
64	export function quote({ items, years }: { items: Item[]; years: number; priorContract: boolean }): { premium: number } {
65	  const basePremium = calculateBasePremium(items);
66	  const firstInsuranceSurcharges = items.length * FIRST_INSURANCE_SURCHARGE;
67	  return { premium: basePremium - loyaltyDiscount(basePremium, years) + firstInsuranceSurcharges + PROCESSING_FEE };
68	}
69	
70	export function claim(_input: unknown): unknown {
71	  return undefined;
72	}
